// // This is a 2-bit binary counter with an active-low synchronous reset and an disable signal.
module top_module (
	input clk,
	input reset,
	input enable,
	output reg [1:0] count);always @(posedge clk) begin
	if (reset)
		count <= 2'b00;
	else if (enable)
		count <= count + 1'b1;
end

endmodule
